#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=4e5+5;
long long a[MAXN],sum[MAXN],ans;
int q[MAXN],l,r,n;
int main(void){
    n=read();
    for (int i=1;i<=n;++i)
    {
        a[i]=read();
        a[n+i]=a[i];
    }
    for(int i=1;i<=2*n;++i)
    {
        sum[i]=sum[i-1]+a[i];
    }
    l=r=1;
    ans=-0x3f3f3f3f3f3f3f3f;
    for(int i=1;i<=2*n;++i)
    {
        while(l<=r&&q[l]<i-n)
        {
            ++l;
        }
        ans=max(ans,sum[i]-sum[q[l]]);
        while(l<=r&&sum[i]<sum[q[r]])
        {
            --r;
        }
        q[++r]=i;
    }
    write(ans);
    return false;
 }
